System.register("chunks:///_virtual/resShiCi.ts",["cc"],(function(n){var t;return{setters:[function(n){t=n.cclegacy}],execute:function(){var i;t._RF.push({},"643a9u1MNVO2JSqgq38lOF8","resShiCi",void 0),n("default",function(){function n(){}return n.getRandomShiCi=function(){var t=Math.floor(Math.random()*Object.keys(n.shiCi).length)+1;return n.shiCi[t]},n}()).shiCi=((i={})[1]="（唐）孟浩然\n春眠不觉晓，处处闻啼鸟。\n夜来风雨声，花落知多少？",i[2]="（唐）王之焕\n白日依山尽，黄河入海流。\n欲穷千里目，更上一层楼。",i[3]="（唐）柳宗元\n千山鸟飞绝，万径人踪灭。\n孤舟蓑笠翁，独钓寒江雪。",i[4]="（唐）贾岛\n松下问童子，言师采药去。\n只在此山中，云深不知处。",i[5]="（唐）李商隐\n向晚意不适，驱车登古原。\n夕阳无限好，只是近黄昏。",i[6]="（宋）李清照\n生当作人杰，死亦为鬼雄。\n至今思项羽，不肯过江东。",i[7]="（宋）林升\n山外青山楼外楼，西湖歌舞几时休？\n暖风熏得游人醉，直把杭州作汴州。",i[8]="（宋）苏轼\n水光潋滟晴方好，山色空蒙雨亦奇。\n欲把西湖比西子，淡妆浓抹总相宜。",i[9]="（宋）辛弃疾\n青山遮不住，毕竟东流去。\n江晚正愁余，山深闻鹧鸪。",i[10]="（宋）陆游\n山重水复疑无路，柳暗花明又一村。\n黄四娘家花满蹊，千朵万朵压枝低。",i[11]="（宋）杨万里\n小荷才露尖尖角，早有蜻蜓立上头。\n接天莲叶无穷碧，映日荷花别样红。",i[12]="（宋）范成大\n梅子金黄杏子肥，麦花雪白菜花稀。\n日长篱落无人过，唯有蜻蜓蛱蝶飞。",i[13]="（宋）王安石\n爆竹声中一岁除，春风送暖入屠苏。\n千门万户瞳瞳日，总把新桃换旧符。",i[14]="（宋）王安石\n春宵一刻值千金，花有清香月有阴。\n歌管楼台声细细，秋千院落夜沉沉。",i[15]="（宋）欧阳修\n去年元夜时，花市灯如昼。\n月上柳梢头，人约黄昏后。",i[16]="（宋）辛弃疾\n众里寻他千百度，蓦然回首，\n那人却在，灯火阑珊处。",i[17]="（宋）苏轼\n明月几时有，把酒问青天。\n不知天上宫阙，今夕是何年。",i[18]="（唐）王之焕\n黄河远上白云间，一片孤城万仞山。\n羌笛何须怨杨柳，春风不度玉门关。",i[19]="（唐）王翰\n葡萄美酒夜光杯，欲饮琵琶马上催。\n醉卧沙场君莫笑，古来征战几人回？",i[20]="（唐）王昌龄\n秦时明月汉时关，万里长征人未还。\n但使龙城飞将在，不教胡马度阴山！",i[21]="（唐）李白\n日照香炉生紫烟，遥看瀑布挂前川。\n飞流直下三千尺，疑是银河落九天。",i[22]="（唐）李白\n故人西辞黄鹤楼，烟花三月下扬州。\n孤帆远影碧空尽，惟见长江天际流。",i[23]="（唐）李白\n天门中断楚江开，碧水东流至此回。\n两岸青山相对出，孤帆一片日边来。",i[24]="（唐）李白\n朝辞白帝彩云间，千里江陵一日还。\n两岸猿声啼不住，轻舟已过万重山。",i[25]="（唐）杜甫\n两个黄鹂鸣翠柳，一行白鹭上青天。\n窗含西岭千秋雪，门泊东吴万里船。",i[26]="（唐）杜甫\n国破山河在，城春草木深。\n感时花溅泪，恨别鸟惊心。",i[27]="（唐）杜甫\n烽火连三月，家书抵万金。\n白头搔更短，浑欲不胜簪。",i[28]="（唐）杜甫\n迟日江山丽，春风花草香。\n泥融飞燕子，沙暖睡鸳鸯。",i[29]="（唐）杜甫\n江碧鸟逾白，山青花欲燃。\n今春看又过，何日是归年？",i),t._RF.pop()}}}));

